 * @Email 2370032534@qq.com
 */
@Configuration
public class WebSocketConfig {

    @Resource
    UserService userService;

    @Resource
    MessageService messageService;

    /**
     * 注入一个ServerEndpointExporter,该Bean会自动注册使用@ServerEndpoint注解申明的websocket endpoint
